//! Spec-compliance tests: Underline Style Roundtrip Fidelity
//! (ISO 29500-1 §17.3.2.40, §17.18.99 ST_Underline)
//!
//! These tests verify that underline style variants (double, dotted, dash,
//! wave, etc.) survive import -> serializer -> export. The serializer must
//! preserve `StyleProps.underline_style` through `build_rpr`.
//!
//! Fixture DOCX files are generated by
//! `testdata/spec-compliance/run-underline-fidelity/create_docs.py`.

use std::fs;
use std::io::{Cursor, Read as _};

use stemma::domain::UnderlineStyle;
use stemma::{DocxRuntime, ExportMode, InlineNode, Mark, SimpleRuntime, TransactionMeta};
use zip::ZipArchive;

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/run-underline-fidelity";

// ── helpers ──────────────────────────────────────────────────────────────

fn text_nodes(p: &stemma::ParagraphNode) -> Vec<stemma::TextNode> {
    p.all_inlines_owned()
        .into_iter()
        .filter_map(|i| match i {
            InlineNode::Text(t) => Some(*t),
            _ => None,
        })
        .collect()
}

/// Import before.docx and after.docx, run diff_and_redline (which
/// triggers `serialize_canonical_docx` -> `build_rpr`), then export
/// and return the raw word/document.xml for XML-level assertions.
fn serialize_roundtrip_xml(fixture_name: &str) -> String {
    let before_path = format!("{FIXTURES}/{fixture_name}/before.docx");
    let after_path = format!("{FIXTURES}/{fixture_name}/after.docx");

    let before_bytes = fs::read(&before_path).unwrap_or_else(|e| panic!("read {before_path}: {e}"));
    let after_bytes = fs::read(&after_path).unwrap_or_else(|e| panic!("read {after_path}: {e}"));

    let runtime = SimpleRuntime::new();
    let import_before = runtime
        .import_docx(&before_bytes)
        .unwrap_or_else(|e| panic!("import {before_path}: {e:?}"));
    let import_after = runtime
        .import_docx(&after_bytes)
        .unwrap_or_else(|e| panic!("import {after_path}: {e:?}"));

    let meta = TransactionMeta {
        author: "spec_run_underline_fidelity".to_string(),
        reason: Some("underline fidelity test".to_string()),
        timestamp_utc: Some("2025-01-15T10:30:00Z".to_string()),
    };
    let apply = runtime
        .diff_and_redline(&import_before.doc_handle, &import_after.doc_handle, meta)
        .expect("diff_and_redline");
    assert!(apply.applied, "redline should be applied");

    let exported = runtime
        .export_docx(&import_before.doc_handle, ExportMode::Redline)
        .expect("export");

    extract_document_xml(&exported)
}

fn extract_document_xml(docx_bytes: &[u8]) -> String {
    let cursor = Cursor::new(docx_bytes);
    let mut zip = ZipArchive::new(cursor).expect("open DOCX zip");
    let mut file = zip
        .by_name("word/document.xml")
        .expect("DOCX must contain word/document.xml");
    let mut out = String::new();
    file.read_to_string(&mut out)
        .expect("read word/document.xml");
    out
}

/// Extract a short snippet around the first `w:u` occurrence in the XML
/// for diagnostic messages.
fn extract_w_u_snippet(xml: &str) -> String {
    for term in ["w:u ", "<u "] {
        if let Some(pos) = xml.find(term) {
            let start = pos.saturating_sub(20);
            let end = (pos + 80).min(xml.len());
            return format!("...{}...", &xml[start..end]);
        }
    }
    "(no w:u element found in document.xml)".to_string()
}

// ── Test 1: double underline roundtrip ──────────────────────────────────

/// Verifies that w:u w:val="double" survives the serializer roundtrip
/// per ISO 29500-1 §17.3.2.40. The before/after fixture pair forces
/// diff_and_redline through the serialize path.
#[test]

fn spec_underline_double_preserved_on_roundtrip() {
    let xml = serialize_roundtrip_xml("roundtrip-double");

    assert!(
        xml.contains("w:val=\"double\""),
        "exported XML should contain w:u w:val=\"double\" after serializer roundtrip.\n\
         The serializer collapsed the style to \"single\".\n\
         Relevant XML snippet: {}",
        extract_w_u_snippet(&xml)
    );
}

