// ── Test 5: multi-style import correctness ──────────────────────────────

/// ISO 29500-1 §17.18.99 ST_Underline: Each underline style variant must
/// be correctly imported into `StyleProps.underline_style`.
///
/// This test verifies the import side (which works correctly).
#[test]
fn spec_underline_style_imported_correctly() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "multi-style");

    let paras = common::all_paragraphs(&doc);
    assert!(!paras.is_empty(), "should have at least one paragraph");

    let nodes = text_nodes(paras[0]);

    let expected: &[(&str, UnderlineStyle)] = &[
        ("single", UnderlineStyle::Single),
        ("double", UnderlineStyle::Double),
        ("dotted", UnderlineStyle::Dotted),
        ("dash", UnderlineStyle::Dash),
        ("wave", UnderlineStyle::Wave),
        ("thick", UnderlineStyle::Thick),
        ("dashLong", UnderlineStyle::DashLong),
        ("dotDash", UnderlineStyle::DotDash),
        ("wavyDouble", UnderlineStyle::WavyDouble),
    ];

    for (label, expected_style) in expected {
        let node = nodes
            .iter()
            .find(|t| t.text.contains(label))
            .unwrap_or_else(|| {
                panic!(
                    "should have a run containing '{label}'. \
                     Available runs: {:?}",
                    nodes.iter().map(|t| &t.text).collect::<Vec<_>>()
                )
            });

        // Every underline run must carry Mark::Underline
        assert!(
            node.marks.contains(&Mark::Underline),
            "run '{label}' should have Mark::Underline, got marks: {:?}",
            node.marks
        );

        // The specific underline style must be preserved in style_props
        assert_eq!(
            node.style_props.underline_style,
            Some(expected_style.clone()),
            "run '{label}' should have underline_style={expected_style:?}, \
             got {:?}",
            node.style_props.underline_style
        );
    }
}
